module top_module(
  input in,
  input Vthp,
  input Vthn,
  output out
);reg unused_prev_out;

  always @(in or Vthp or Vthn or unused_prev_out) begin
    if (in > Vthp) begin
      unused_prev_out <= 1;
    end else if (in < Vthn) begin
      unused_prev_out <= 0;
    end
  end

  assign out = unused_prev_out;

endmodule
